const PROCESSING_FEE = 5;
const SWORD_BASE_PREMIUM = 100;
const FIRST_INSURANCE_SURCHARGE = 10;

type Item = { type: string };
type QuoteStep = { op: "quote"; items: Item[] };
type Step = QuoteStep;
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };

const quotePremium = (items: Item[]): number => {
  if (items.length === 0) return PROCESSING_FEE;
  return SWORD_BASE_PREMIUM + FIRST_INSURANCE_SURCHARGE + PROCESSING_FEE;
};

export const runScenario = (scenario: Scenario): { results: Array<{ premium: number }> } => ({
  results: scenario.steps.map((step) => ({ premium: quotePremium(step.items) })),
});
